<template>
    <DashboardLayout
        :headerImage="require('@/assets/BI驾驶舱/头部.png')"
        :backgroundImage="require('@/assets/BI驾驶舱/背景.png')"
        @back="goBack"
        @admin="goAdmin"
    >
        <!-- 左侧面板 -->
        <template #left>
            <!-- 水源取水统计 -->
            <DashboardCard title="水源取水统计" :titleBg="require('@/assets/BI驾驶舱/小标题头部.png')">
                    <div class="stat-row">
                        <div class="stat-item">
                            <div class="stat-label">总取水量(m³)</div>
                            <div class="stat-value">125460.75</div>
                            <div class="stat-trend up">
                                <img src="@/assets/BI驾驶舱/上升.png" alt="上升" />
                                <span>0.87%</span>
                            </div>
                        </div>
                        <div class="stat-item">
                            <div class="stat-label">供水流量(m³/h)</div>
                            <div class="stat-value">0.13</div>
                            <div class="stat-trend up">
                                <img src="@/assets/BI驾驶舱/上升.png" alt="上升" />
                                <span>0.67%</span>
                            </div>
                        </div>
                        <div class="stat-item">
                            <div class="stat-label">水源合格率</div>
                            <div class="stat-value">100.00%</div>
                        </div>
                    </div>
                    <div class="water-chart">
                        <div class="chart-row">
                            <div class="chart-label">日取水量</div>
                            <div class="chart-icons">
                                <img src="@/assets/BI驾驶舱/日取水量.png" v-for="i in 10" :key="'water-' + i" alt="水滴" />
                            </div>
                            <div class="chart-value">860m³</div>
                        </div>
                        <div class="chart-row">
                            <div class="chart-label">日能耗</div>
                            <div class="chart-icons">
                                <img src="@/assets/BI驾驶舱/日能耗.png" v-for="i in 10" :key="'energy-' + i" alt="能耗" />
                            </div>
                            <div class="chart-value">1100.27kw</div>
                        </div>
                    </div>
            </DashboardCard>

            <!-- 水厂生产解析 -->
            <DashboardCard title="水厂生产解析" :titleBg="require('@/assets/BI驾驶舱/小标题头部.png')">
                    <div class="stat-row">
                        <div class="stat-item">
                            <div class="stat-label">日供水量(m³)</div>
                            <div class="stat-value">9210</div>
                            <div class="stat-trend down">
                                <img src="@/assets/BI驾驶舱/下降.png" alt="下降" />
                                <span>0.42%</span>
                            </div>
                        </div>
                        <div class="stat-item">
                            <div class="stat-label">供水流量(m³/h)</div>
                            <div class="stat-value">0.26</div>
                            <div class="stat-trend up">
                                <img src="@/assets/BI驾驶舱/上升.png" alt="上升" />
                                <span>1.16%</span>
                            </div>
                        </div>
                        <div class="stat-item">
                            <div class="stat-label">水质合格率</div>
                            <div class="stat-value">100.00%</div>
                        </div>
                    </div>
                    <div class="production-chart">
                        <div ref="productionChart" class="chart-canvas"></div>
                    </div>
            </DashboardCard>

            <!-- 泵站能耗分析 -->
            <DashboardCard title="泵站能耗分析" :titleBg="require('@/assets/BI驾驶舱/小标题头部.png')">
                    <div class="stat-row">
                        <div class="stat-item">
                            <div class="stat-label">日供水量(m³)</div>
                            <div class="stat-value">1238</div>
                            <div class="stat-trend down">
                                <img src="@/assets/BI驾驶舱/下降.png" alt="下降" />
                                <span>10.28%</span>
                            </div>
                        </div>
                        <div class="stat-item">
                            <div class="stat-label">日能耗(kwh)</div>
                            <div class="stat-value">133.15</div>
                            <div class="stat-trend down">
                                <img src="@/assets/BI驾驶舱/下降.png" alt="下降" />
                                <span>69.89%</span>
                            </div>
                        </div>
                        <div class="stat-item">
                            <div class="stat-label">吨水电量(kwh/m³)</div>
                            <div class="stat-value">0.11</div>
                            <div class="stat-trend up">
                                <img src="@/assets/BI驾驶舱/上升.png" alt="上升" />
                                <span>2.79%</span>
                            </div>
                        </div>
                    </div>
                    <div class="line-chart">
                        <div ref="lineChart" class="chart-canvas"></div>
                    </div>
            </DashboardCard>
        </template>

        <!-- 中央区域 -->
        <template #center>
            <div class="map-container">
                <div class="map-content">
                    <!-- 地图区域会放置在这里 -->
                    <div class="map-placeholder">
                        <div class="map-text">城乡供水地图</div>
                    </div>
                </div>
                <!-- 弹框信息 -->
                <div class="map-popup" v-if="showPopup" :style="popupStyle">
                    <img src="@/assets/BI驾驶舱/弹框.png" alt="弹框" class="popup-bg" />
                    <div class="popup-content">
                        <div class="popup-title">{{ popupData.title }}</div>
                        <div class="popup-info">
                            <div>{{ popupData.info1 }}</div>
                            <div>{{ popupData.info2 }}</div>
                        </div>
                    </div>
                </div>
            </div>

            <!-- 底部用水数据 -->
            <div class="water-usage">
                <div class="usage-item">
                    <div class="usage-cube">
                        <img src="@/assets/BI驾驶舱/用水背景.png" alt="背景" class="cube-img" />
                        <div class="cube-glow"></div>
                    </div>
                    <div class="usage-content">
                        <div class="usage-label">生活用水(m³)</div>
                        <div class="usage-value">195924</div>
                        <div class="usage-percent">100%</div>
                    </div>
                </div>
                <div class="usage-item">
                    <div class="usage-cube">
                        <img src="@/assets/BI驾驶舱/用水背景.png" alt="背景" class="cube-img" />
                        <div class="cube-glow"></div>
                    </div>
                    <div class="usage-content">
                        <div class="usage-label">工业用水(m³)</div>
                        <div class="usage-value">0</div>
                        <div class="usage-percent">0%</div>
                    </div>
                </div>
                <div class="usage-item">
                    <div class="usage-cube">
                        <img src="@/assets/BI驾驶舱/用水背景.png" alt="背景" class="cube-img" />
                        <div class="cube-glow"></div>
                    </div>
                    <div class="usage-content">
                        <div class="usage-label">商业用水(m³)</div>
                        <div class="usage-value">0</div>
                        <div class="usage-percent">0%</div>
                    </div>
                </div>
                <div class="usage-item">
                    <div class="usage-cube">
                        <img src="@/assets/BI驾驶舱/用水背景.png" alt="背景" class="cube-img" />
                        <div class="cube-glow"></div>
                    </div>
                    <div class="usage-content">
                        <div class="usage-label">混合用水(m³)</div>
                        <div class="usage-value">2647</div>
                        <div class="usage-percent">0%</div>
                    </div>
                </div>
            </div>
        </template>

        <!-- 右侧面板 -->
        <template #right>
            <!-- 管网监测分析 -->
            <DashboardCard title="管网监测分析" :titleBg="require('@/assets/BI驾驶舱/小标题头部.png')">
                    <div class="network-analysis">
                        <div class="network-stats">
                            <div class="network-stat-item">
                                <div class="stat-label">管网总长(Km)</div>
                                <div class="stat-value">325.78</div>
                            </div>
                            <div class="network-stat-item">
                                <div class="stat-label">覆盖面积(Km²)</div>
                                <div class="stat-value">1152.78</div>
                            </div>
                            <div class="network-stat-item">
                                <div class="stat-label">压力合格率</div>
                                <div class="stat-value">100.00%</div>
                            </div>
                            <div class="network-stat-item">
                                <div class="stat-label">水质合格率</div>
                                <div class="stat-value">100.00%</div>
                            </div>
                        </div>
                        <div class="coverage-rate">
                            <img src="@/assets/BI驾驶舱/管网监测分析环图背景.png" alt="背景" class="coverage-bg-img" />
                            <div ref="coverageChart" class="coverage-chart"></div>
                        </div>
                    </div>
            </DashboardCard>

            <!-- DMA监测分析 -->
            <DashboardCard title="DMA监测分析" :titleBg="require('@/assets/BI驾驶舱/小标题头部.png')">
                    <div class="stat-row">
                        <div class="stat-item">
                            <div class="stat-label">日间流量(m³)</div>
                            <div class="stat-value">119857103</div>
                            <div class="stat-trend up">
                                <img src="@/assets/BI驾驶舱/上升.png" alt="上升" />
                                <span>10.12.2%</span>
                            </div>
                        </div>
                        <div class="stat-item">
                            <div class="stat-label">日漏损量(m³)</div>
                            <div class="stat-value">424.8</div>
                            <div class="stat-trend up">
                                <img src="@/assets/BI驾驶舱/上升.png" alt="上升" />
                                <span>4.16%</span>
                            </div>
                        </div>
                        <div class="stat-item">
                            <div class="stat-label">日漏损率</div>
                            <div class="stat-value">0.04%</div>
                            <div class="stat-trend down">
                                <img src="@/assets/BI驾驶舱/下降.png" alt="下降" />
                                <span>99.60%</span>
                            </div>
                        </div>
                    </div>
                    <div class="dma-chart">
                        <div ref="dmaChart" class="chart-canvas"></div>
                    </div>
            </DashboardCard>

            <!-- 本月工单考核 -->
            <DashboardCard title="本月工单考核" :titleBg="require('@/assets/BI驾驶舱/小标题头部.png')">
                    <div class="monthly-stats">
                        <div class="stats-grid">
                            <div class="stat-box">
                                <div class="stat-label">处理中</div>
                                <div class="stat-value">0</div>
                            </div>
                            <div class="stat-box">
                                <div class="stat-label">待审批</div>
                                <div class="stat-value">0</div>
                            </div>
                            <div class="stat-box">
                                <div class="stat-label">已审批</div>
                                <div class="stat-value">0</div>
                            </div>
                        </div>
                        <div class="completion-display">
                            <img src="@/assets/BI驾驶舱/完成率背景.png" alt="完成率背景" class="completion-bg" />
                            <div class="completion-info">
                                <div class="completion-value">0.00%</div>
                                <div class="completion-label">工单完成率</div>
                            </div>
                        </div>
                    </div>
            </DashboardCard>

            <!-- 本月巡检任务 -->
            <DashboardCard title="本月巡检任务" :titleBg="require('@/assets/BI驾驶舱/小标题头部.png')">
                    <div class="monthly-stats">
                        <div class="stats-grid">
                            <div class="stat-box">
                                <div class="stat-label">新增巡检</div>
                                <div class="stat-value">4</div>
                            </div>
                            <div class="stat-box">
                                <div class="stat-label">发现隐患</div>
                                <div class="stat-value">0</div>
                            </div>
                            <div class="stat-box">
                                <div class="stat-label">完成巡检</div>
                                <div class="stat-value">0</div>
                            </div>
                            <div class="stat-box">
                                <div class="stat-label">巡检执行率</div>
                                <div class="stat-value">50</div>
                            </div>
                        </div>
                        <div class="completion-display">
                            <img src="@/assets/BI驾驶舱/完成率背景.png" alt="完成率背景" class="completion-bg" />
                            <div class="completion-info">
                                <div class="completion-value">25.00%</div>
                                <div class="completion-label">巡检完成率</div>
                            </div>
                        </div>
                    </div>
            </DashboardCard>
        </template>
    </DashboardLayout>
</template>

<script>
import { markRaw } from 'vue'
import * as echarts from 'echarts'
import DashboardLayout from '@/components/DashboardLayout.vue'
import DashboardCard from '@/components/DashboardCard.vue'

export default {
  components: {
    DashboardLayout,
    DashboardCard
  },
  name: 'BIDashboard',
  data() {
    return {
      currentTime: '',
      showPopup: false,
      popupStyle: {},
      popupData: {
        title: '陵区',
        info1: '城区区块取水量来源：白桥',
        info2: '状态：正常 日取水量：100.25(m³)'
      },
      productionChartInstance: null,
      lineChartInstance: null,
      dmaChartInstance: null,
      coverageChartInstance: null
    }
  },
  mounted() {
    this.updateTime()
    setInterval(this.updateTime, 1000)
    this.$nextTick(() => {
      this.initCharts()
    })
    window.addEventListener('resize', this.handleResize)
  },
  beforeUnmount() {
    window.removeEventListener('resize', this.handleResize)
    if (this.productionChartInstance) this.productionChartInstance.dispose()
    if (this.lineChartInstance) this.lineChartInstance.dispose()
    if (this.dmaChartInstance) this.dmaChartInstance.dispose()
    if (this.coverageChartInstance) this.coverageChartInstance.dispose()
  },
  methods: {
    updateTime() {
      const now = new Date()
      const year = now.getFullYear()
      const month = String(now.getMonth() + 1).padStart(2, '0')
      const day = String(now.getDate()).padStart(2, '0')
      const hours = String(now.getHours()).padStart(2, '0')
      const minutes = String(now.getMinutes()).padStart(2, '0')
      const seconds = String(now.getSeconds()).padStart(2, '0')
      const weekDays = ['星期日', '星期一', '星期二', '星期三', '星期四', '星期五', '星期六']
      const weekDay = weekDays[now.getDay()]
      this.currentTime = `${year}/${month}/${day} ${hours}:${minutes}:${seconds} ${weekDay}`
    },
    goBack() {
      this.$router.push('/')
    },
    goAdmin() {
      console.log('进入后台')
    },
    handleResize() {
      if (this.productionChartInstance) this.productionChartInstance.resize()
      if (this.lineChartInstance) this.lineChartInstance.resize()
      if (this.dmaChartInstance) this.dmaChartInstance.resize()
      if (this.coverageChartInstance) this.coverageChartInstance.resize()
    },
    initCharts() {
      this.drawProductionChart()
      this.drawLineChart()
      this.drawDMAChart()
      this.drawCoverageChart()
    },
    // 水厂生产解析 - 柱状图+折线图
    drawProductionChart() {
      const chartDom = this.$refs.productionChart
      if (!chartDom) return
      
      // 高清渲染配置
      this.productionChartInstance = echarts.init(chartDom, null, {
        devicePixelRatio: window.devicePixelRatio || 2
      })
      const option = {
        grid: {
          left: '12%',
          right: '5%',
          top: '15%',
          bottom: '15%'
        },
        tooltip: {
          trigger: 'axis',
          backgroundColor: 'rgba(0, 20, 40, 0.9)',
          borderColor: '#00d4ff',
          borderWidth: 1,
          textStyle: {
            color: '#fff'
          }
        },
        legend: {
          data: ['供水量', '取水量', '供取比'],
          top: '0%',
          textStyle: {
            color: '#00d4ff',
            fontSize: 12
          },
          itemWidth: 15,
          itemHeight: 10
        },
        xAxis: {
          type: 'category',
          data: ['06-22', '06-23', '06-24', '06-25', '06-26', '06-27', '06-28'],
          axisLine: {
            lineStyle: {
              color: 'rgba(0, 212, 255, 0.3)'
            }
          },
          axisLabel: {
            color: '#00d4ff',
            fontSize: 11
          }
        },
        yAxis: [
          {
            type: 'value',
            name: '水量',
            position: 'left',
            axisLine: {
              show: false
            },
            axisTick: {
              show: false
            },
            splitLine: {
              lineStyle: {
                color: 'rgba(0, 212, 255, 0.1)'
              }
            },
            axisLabel: {
              color: '#00d4ff',
              fontSize: 11
            }
          },
          {
            type: 'value',
            name: '比率(%)',
            position: 'right',
            axisLine: {
              show: false
            },
            axisTick: {
              show: false
            },
            splitLine: {
              show: false
            },
            axisLabel: {
              color: '#ffa500',
              fontSize: 11,
              formatter: '{value}%'
            }
          }
        ],
        series: [
          {
            name: '供水量',
            type: 'bar',
            yAxisIndex: 0,
            data: [120, 132, 101, 134, 90, 130, 110],
            itemStyle: {
              color: new echarts.graphic.LinearGradient(0, 0, 0, 1, [
                { offset: 0, color: '#00d4ff' },
                { offset: 1, color: 'rgba(0, 212, 255, 0.3)' }
              ])
            },
            barWidth: 15,
            barGap: '20%'
          },
          {
            name: '取水量',
            type: 'bar',
            yAxisIndex: 0,
            data: [135, 145, 115, 150, 105, 145, 125],
            itemStyle: {
              color: new echarts.graphic.LinearGradient(0, 0, 0, 1, [
                { offset: 0, color: '#52c41a' },
                { offset: 1, color: 'rgba(82, 196, 26, 0.3)' }
              ])
            },
            barWidth: 15
          },
          {
            name: '供取比',
            type: 'line',
            yAxisIndex: 1,
            data: [88.9, 91.0, 87.8, 89.3, 85.7, 89.7, 88.0],
            smooth: true,
            lineStyle: {
              color: '#ffa500',
              width: 3
            },
            itemStyle: {
              color: '#ffa500',
              borderWidth: 2
            },
            symbol: 'circle',
            symbolSize: 8,
            areaStyle: {
              color: new echarts.graphic.LinearGradient(0, 0, 0, 1, [
                { offset: 0, color: 'rgba(255, 165, 0, 0.3)' },
                { offset: 1, color: 'rgba(255, 165, 0, 0.05)' }
              ])
            }
          }
        ]
      }
      this.productionChartInstance.setOption(option)
    },
    // 泵站能耗分析 - 折线图
    drawLineChart() {
      const chartDom = this.$refs.lineChart
      if (!chartDom) return
      
      // 高清渲染配置
      this.lineChartInstance = markRaw(echarts.init(chartDom, null, {
        devicePixelRatio: window.devicePixelRatio || 2
      }))
      const option = {
        grid: {
          left: '12%',
          right: '5%',
          top: '15%',
          bottom: '15%'
        },
        tooltip: {
          trigger: 'axis',
          backgroundColor: 'rgba(0, 20, 40, 0.9)',
          borderColor: '#00d4ff',
          borderWidth: 1,
          textStyle: {
            color: '#fff'
          }
        },
        legend: {
          data: ['昨日', '今日', '近7日平均'],
          top: '0%',
          textStyle: {
            color: '#00d4ff',
            fontSize: 12
          },
          itemWidth: 20,
          itemHeight: 10
        },
        xAxis: {
          type: 'category',
          data: ['03:00', '06:00', '09:00', '12:00', '15:00', '18:00', '21:00', '00:00'],
          axisLine: {
            lineStyle: {
              color: 'rgba(0, 212, 255, 0.3)'
            }
          },
          axisLabel: {
            color: '#00d4ff',
            fontSize: 11
          }
        },
        yAxis: {
          type: 'value',
          axisLine: {
            show: false
          },
          axisTick: {
            show: false
          },
          splitLine: {
            lineStyle: {
              color: 'rgba(0, 212, 255, 0.1)'
            }
          },
          axisLabel: {
            color: '#00d4ff',
            fontSize: 11
          }
        },
        series: [
          {
            name: '昨日',
            type: 'line',
            data: [150, 180, 220, 280, 250, 300, 270, 240],
            smooth: true,
            lineStyle: {
              color: '#00d4ff',
              width: 2
            },
            itemStyle: {
              color: '#00d4ff'
            },
            areaStyle: {
              color: new echarts.graphic.LinearGradient(0, 0, 0, 1, [
                { offset: 0, color: 'rgba(0, 212, 255, 0.4)' },
                { offset: 1, color: 'rgba(0, 212, 255, 0.05)' }
              ])
            }
          },
          {
            name: '今日',
            type: 'line',
            data: [160, 190, 230, 290, 260, 310, 280, 250],
            smooth: true,
            lineStyle: {
              color: '#52c41a',
              width: 2
            },
            itemStyle: {
              color: '#52c41a'
            },
            areaStyle: {
              color: new echarts.graphic.LinearGradient(0, 0, 0, 1, [
                { offset: 0, color: 'rgba(82, 196, 26, 0.4)' },
                { offset: 1, color: 'rgba(82, 196, 26, 0.05)' }
              ])
            }
          },
          {
            name: '近7日平均',
            type: 'line',
            data: [155, 185, 225, 285, 255, 305, 275, 245],
            smooth: true,
            lineStyle: {
              color: '#ffa500',
              width: 2,
              type: 'dashed'
            },
            itemStyle: {
              color: '#ffa500'
            }
          }
        ]
      }
      this.lineChartInstance.setOption(option)
    },
    // DMA监测分析 - 柱状图+折线图
    drawDMAChart() {
      const chartDom = this.$refs.dmaChart
      if (!chartDom) return
      
      // 高清渲染配置
      this.dmaChartInstance = echarts.init(chartDom, null, {
        devicePixelRatio: window.devicePixelRatio || 2
      })
      const option = {
        grid: {
          left: '12%',
          right: '12%',
          top: '18%',
          bottom: '15%'
        },
        tooltip: {
          trigger: 'axis',
          backgroundColor: 'rgba(0, 20, 40, 0.9)',
          borderColor: '#00d4ff',
          borderWidth: 1,
          textStyle: {
            color: '#fff'
          },
          axisPointer: {
            type: 'shadow',
            shadowStyle: {
              color: 'rgba(0, 212, 255, 0.1)'
            }
          }
        },
        legend: {
          data: ['供水量', '漏损量', '漏损率'],
